#include "ph_sensor.h"
#include <Arduino.h>
#define PH_PIN 34
#define PH_OFFSET 0.0
static float _ph=7.0,_v=0;static unsigned long _l=0;
void ph_setup(){Serial.println("[ph] OK");}
void ph_loop(){if(millis()-_l<1000)return;_l=millis();int r=0;for(int i=0;i<10;i++)r+=analogRead(PH_PIN);_v=r/10.0*3.3/4095.0;_ph=3.5*_v+PH_OFFSET;}
float ph_get_value(){return _ph;}
float ph_get_voltage(){return _v;}
